def test_static_file_server_returns_text_file() -> None:
    """Tests serving a plain text file with Cache-Control headers."""
    import os  # noqa: PLC0415
    import urllib.request  # noqa: PLC0415
    base = os.environ.get("SUT_URL", "http://127.0.0.1:8000")
    url = f"{base}/fixtures/static_file_server_returns_text_file/public/hello.txt"
    _headers = {}
    _req = urllib.request.Request(url, headers=_headers, method="GET")
    class _NoRedirect(urllib.request.HTTPRedirectHandler):  # noqa: N801
        def redirect_request(self, *args, **kwargs):
            return None
    _opener = urllib.request.build_opener(_NoRedirect())
    try:
        response = _opener.open(_req)  # noqa: S310
        status_code = response.status
        resp_body = response.read()  # noqa: F841
        resp_headers = dict(response.headers)  # noqa: F841
    except urllib.error.HTTPError as _exc:
        status_code = _exc.code
        resp_body = _exc.read()  # noqa: F841
        resp_headers = dict(_exc.headers)  # noqa: F841
    assert status_code == 200  # noqa: S101
    assert resp_body.decode() == "Hello from static storage"  # noqa: S101
    assert resp_headers["cache-control"] == "public, max-age=60"  # noqa: S101
    assert resp_headers["content-type"] == "text/plain"  # noqa: S101

